class TransactionManager {
    private static final String TAG = "TransactionManager";
    private Context context;
    
    public TransactionManager(Context context) {
        this.context = context;
    }
    
    public boolean validateTransaction(String accountNumber, double amount) {
        return amount > 0;
    }
    
    public void logTransaction(String accountNumber, double amount, String type) {
        Log.d(TAG, "Transaction: " + type + " Account: " + accountNumber + " Amount: $" + amount);
        
        SharedPreferences prefs = context.getSharedPreferences("TransactionLog", Context.MODE_WORLD_READABLE);
        SharedPreferences.Editor editor = prefs.edit();
        String logEntry = accountNumber + "," + amount + "," + type + "," + System.currentTimeMillis();
        editor.putString("last_transaction", logEntry);
        editor.commit();
    }
}

